# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
import json

# Set the RabbitMQ Management HTTP API endpoint
url = "http://guest:guest@localhost:15672/api/"

def create_vhost(name):
    vhost_url = url + f'vhosts/{name}'
    response = requests.put(vhost_url)
    
    if response.status_code == 204 or response.status_code == 406:
        print("Virtual Host created successfully")
    else:
        print(f"Failed to create Virtual host, status code: {response.status_code}")
        
def configure_user(username, password):
    user_url = url + f'users/{username}'
    
    # Set the user details
    user_data = json.dumps({'password': password, 'tags': ''})
    response = requests.put(user_url, data=user_data)
    
    if response.status_code == 204:
        print("User configured successfully")
    else:
        print(f"Failed to configure user, status code: {response.status_code}") 
        
def set_permissions(username, vhost):
    perm_url = url + f'permissions/{vhost}/{username}'
    
    # Set the permission details (all permissions)
    perm_data = json.dumps({'configure': '.', 'write': '.', 'read': '.'})
    response = requests.put(perm_url, data=perm_data)
    
    if response.status_code == 204:
        print("Permissions set successfully")
    else:
        print(f"Failed to set permissions, status code: {response.status_code}") 
        
# Call the functions
create_vhost('my_vhost')
configure_user('my_username', 'my_password')
set_permissions('my_username', 'my_vhost')